import React, { useEffect, useState, useRef } from "react";
import { useNavigate, Link } from "react-router-dom";
import "../styles/Certificado.css";

const CertificadoBancario = () => {
  const navigate = useNavigate();
  const certificadoRef = useRef();

  const [usuario, setUsuario] = useState({
    nombre: "",
    documento: "",
    cuenta: "",
    tipoCuenta: "Ahorros Digital",
    estado: "Activa",
    saldo: "$0 COP",
  });

  // 🔥 Obtener datos reales desde la base de datos
  useEffect(() => {
    const documentoGuardado = localStorage.getItem("documento");

    if (!documentoGuardado) {
      navigate("/inicio");
      return;
    }

    const obtenerUsuario = async () => {
      try {
        const response = await fetch(
          `http://127.0.0.1:8000/usuario-documento/${documentoGuardado}`
        );

        if (!response.ok) {
          throw new Error("No se pudo obtener el usuario");
        }

        const data = await response.json();

        setUsuario({
          nombre: data.nombre || "Usuario",
          documento: data.documento || documentoGuardado,
          cuenta: data.numero_cuenta || "9800456721",
          tipoCuenta: data.tipo_cuenta || "Ahorros Digital",
        });
      } catch (error) {
        console.error("Error al obtener usuario:", error);

        setUsuario({
          nombre: "Usuario",
          documento: documentoGuardado,
          cuenta: "9800456721",
          tipoCuenta: "Ahorros Digital",
          estado: "Activa",
          saldo: "$0 COP",
        });
      }
    };

    obtenerUsuario();
  }, [navigate]);

  // 🔥 Bloquear botón atrás
  useEffect(() => {
    window.history.pushState(null, "", window.location.href);

    const bloquear = () => {
      window.history.pushState(null, "", window.location.href);
    };

    window.addEventListener("popstate", bloquear);

    return () => {
      window.removeEventListener("popstate", bloquear);
    };
  }, []);

  // 🔥 Cerrar sesión
  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("usuario");
    localStorage.removeItem("documento");
    navigate("/inicio");
  };

  // 🔥 Descargar PDF
  const descargarPDF = () => {
    const element = certificadoRef.current;

    const opciones = {
      margin: 0.5,
      filename: `Certificado_${usuario.documento}.pdf`,
      image: { type: "jpeg", quality: 1 },
      html2canvas: { scale: 2 },
      jsPDF: {
        unit: "in",
        format: "letter",
        orientation: "portrait",
      },
    };

    html2pdf().set(opciones).from(element).save();
  };

  // 🔥 Fecha actual
  const fechaActual = new Date().toLocaleDateString("es-CO", {
    day: "numeric",
    month: "long",
    year: "numeric",
  });

  return (
    <div className="panel-financiero">
      {/* SIDEBAR */}
      <aside className="sidebar">
        <ul>
          <li>
            <Link to="/cuenta">💷 Cuenta</Link>
          </li>

          <li>
            <Link to="#">📜 Historial Monetario</Link>
          </li>

          <li>
            <Link to="/transferencias">💳 Transferencias</Link>
          </li>

          <li>
            <Link to="/certificado" className="active">
              📄 Certificado Bancario
            </Link>
          </li>

          <li>
            <Link to="#">⚙️ Ajustes</Link>
          </li>
        </ul>

        <button className="logout" onClick={handleLogout}>
          🚪 Cerrar sesión
        </button>
      </aside>

      {/* CONTENIDO PRINCIPAL */}
      <main className="main">
        <header className="main-header">
          <h1>Certificado Bancario</h1>

          <div className="profile">
            <img
              src="https://i.pinimg.com/736x/e0/06/16/e00616c1e181f83b35b157f9281bd36e.jpg"
              alt="Usuario"
            />
          </div>
        </header>

        <div className="certificado-container">
          <div className="certificado" ref={certificadoRef}>
            <div className="header">
              <h1>Financiero</h1>
              <h2>Certificado Bancario</h2>
            </div>

            <div className="contenido">
              <p>La presente certifica que el(la) señor(a):</p>

              {/* 🔥 NOMBRE EN MISMO FORMATO NORMAL */}
              <p className="texto-dato">{usuario.nombre}</p>

              <p>Identificado(a) con Cédula de Ciudadanía No:</p>

              {/* 🔥 DOCUMENTO EN MISMO FORMATO NORMAL */}
              <p className="texto-dato">{usuario.documento}</p>

              <p>
                Es titular de una cuenta en nuestra billetera digital con los
                siguientes datos:
              </p>

              <ul>
                <li>
                  <strong>Número de cuenta:</strong> {usuario.cuenta}
                </li>
                <li>
                  <strong>Tipo de cuenta:</strong> {usuario.tipoCuenta}
                </li>
                <li>
                  <strong>Estado:</strong> {usuario.estado}
                </li>
                <li>
                  <strong>Saldo actual:</strong> {usuario.saldo}
                </li>
              </ul>

              <p>
                Este certificado se expide en la ciudad de Bogotá D.C. el día:
              </p>

              <h4 className="fecha">{fechaActual}</h4>
            </div>

            <div className="footer">
              <p>Firma autorizada</p>
              <div className="firma"></div>
              <p>Financiero</p>
            </div>
          </div>
        </div>

        {/* BOTÓN DESCARGAR PDF */}
        <div style={{ textAlign: "center", marginTop: "20px" }}>
          <button className="descargar-btn" onClick={descargarPDF}>
            📥 Descargar Certificado en PDF
          </button>
        </div>
      </main>
    </div>
  );
};

export default CertificadoBancario;
